     3→ *
     4→ * Detailed audit trail preserving all sophisticated classification reasoning
     5→ * per the scoring logic structure defined in SCORING_LOGIC.md.
     6→ */
     7→
     8→export interface ExplainabilityTrace {
     9→  sessionId: string;
    10→  emailId: string;
    11→
    12→  // Pipeline stage results
    13→  hardAssertions: HardAssertionResult[];
    14→  strongIndicators: StrongIndicatorResult[];
    15→  ruleScoring: CategoryRuleResult[]; // Enhanced rule scoring results
    16→  attributeDetection: AttributeDetectionResult[];
    17→  attributeInfluence: AttributeInfluenceResult[];
    18→  disambiguation: DisambiguationResult[];
    19→  multiLabelSelection: MultiLabelResult[];
    20→  aiRouting?: AIRoutingResult;
    21→
    22→  // Enhanced for debugging and parallel processing
    23→  stageTimings: Record<string, number>; // Stage execution times in ms
    24→  parallelExecutionMap: Record<string, string[]>; // Which stages ran in parallel
    25→  configurationRefs: Record<string, string>; // Config sections used
    26→
    27→  // Decision audit
    28→  finalDecisionReason: string;
    29→  alternativeCategories: Array<{
    30→    category: string;
    31→    score: number;
    32→    eliminationReason: string;
    33→  }>;
    34→}
    35→
    36→/**
    37→ * Hard Assertions stage results
    38→ * Implements HIGH_CONFIDENCE_FLOOR logic per SCORING_LOGIC.md
    39→ */
    40→export interface HardAssertionResult {
    41→  category: string;
    42→  triggered: boolean;
    43→  assertionType: 'fromDomain' | 'subjectPrefix' | 'fromAddress';
    44→  matchedValue: string;
    45→  confidence: 'HIGH_CONFIDENCE' | 'MEDIUM_CONFIDENCE'; // From config
    46→  sourceGroup?: string; // Domain source group if applicable
    47→  reason: string;
    48→}
    49→
    50→/**
    51→ * Strong Indicator Seeding stage results
    52→ * Implements diminishing returns seeding per SCORING_LOGIC.md
    53→ */
    54→export interface StrongIndicatorResult {
    55→  category: string;
    56→  indicatorType: 'fromDomain' | 'subjectContains' | 'bodyContains';
    57→  matchedValue: string;
    58→  seedScore: number;
    59→  diminishingReturnsApplied: boolean;
    60→  existingSeedScore: number; // Score before this indicator
    61→  finalSeedScore: number; // Score after diminishing returns
    62→  reason: string;
    63→}
    64→
    65→/**
    66→ * Rule-based Scoring stage results
    67→ * Implements subtype scoring formula with K_high/K_medium/K_low parameters
    68→ */
    69→export interface RuleEvaluationResult {
    70→  category: string;
    71→  subtype: string;
    72→  tier: 'high' | 'medium' | 'low';
    73→  matchedRules: RuleMatch[];
    74→  rawScore: number;
    75→  cappedScore: number;
    76→  tierWeight: number; // K_high, K_medium, or K_low from config
    77→  reason: string;
    78→}
    79→
    80→export interface RuleMatch {
    81→  field: string;
    82→  operation: string;
    83→  matchedValue: string;
    84→  ruleWeight: number;
    85→  partialMatch: boolean;
    86→}
    87→
    88→/**
    89→ * Enhanced rule scoring result types for new implementation
    90→ */
    91→export interface RuleScoringMatch extends RuleMatch {
    92→  tier: 'highConfidence' | 'mediumConfidence' | 'lowConfidence';
    93→  values: string[];
    94→  weight: number;
    95→  ruleId: string;
    96→}
    97→
    98→export interface SubtypeScore {
    99→  totalScore: number;
   100→  ruleMatches: RuleScoringMatch[];
   101→  aggregationBreakdown: string;
   102→}
   103→
   104→export interface CategoryRuleResult {
   105→  categoryCode: string;
   106→  aggregatedScore: number;
   107→  subtypeScores: Record<string, SubtypeScore>;
   108→  ruleMatches: RuleScoringMatch[];
   109→  scoringRationale: string[];
   110→  selectedSubtypeId: string | null;
   111→  confidence: number;
   112→}
   113→
   114→/**
   115→ * Attribute Detection stage results
   116→ * Implements detectors and derived attributes per SCORING_LOGIC.md
   117→ */
   118→export interface AttributeDetectionResult {
   119→  attribute: string;
   120→  detected: boolean;
   121→  detectionMethod: 'direct' | 'derived';
   122→  sourceField?: string; // For direct detection
   123→  derivationLogic?: string; // For derived attributes
   124→  confidence: number;
   125→  parallelProcessed: boolean;
   126→  dependencies: string[]; // Other attributes this detection depended on
   127→  reason: string;
   128→}
   129→
   130→/**
   131→ * Attribute Influence stage results
   132→ * Implements attribute bonus mapping and role enforcement per SCORING_LOGIC.md
   133→ */
   134→export interface AttributeInfluenceResult {
   135→  targetCategory: string;
   136→  attributeUsed: string;
   137→  roleType: 'CORE' | 'PRIMARY_BOOST' | 'SECONDARY_BOOST' | 'DISAMBIGUATOR' | 'FILTER';
   138→  bonusAmount: number;
   139→  scoreBefore: number;
   140→  scoreAfter: number;
   141→  capApplied: boolean;
   142→  reason: string;
   143→}
   144→
   145→/**
   146→ * Disambiguation stage results
   147→ * Implements pairwise adjustments per SCORING_LOGIC.md
   148→ */
   149→export interface DisambiguationResult {
   150→  involvedCategories: string[];
   151→  adjustmentType: 'pairwise' | 'confidenceGap';
   152→  scoreAdjustments: Record<string, number>;
   153→  winningCategory: string;
   154→  confidenceGap: number;
   155→  reason: string;
   156→}
   157→
   158→/**
   159→ * Multi-label Selection stage results
   160→ * Implements selection logic per SCORING_LOGIC.md
   161→ */
   162→export interface MultiLabelResult {
   163→  selectedCategories: string[];
   164→  rejectedCategories: Array<{
   165→    category: string;
   166→    score: number;
   167→    rejectionReason: string;
   168→  }>;
   169→  coPresenceRulesApplied: string[];
   170→  maxLabelsLimit: number;
   171→  minSecondaryConfidence: number;
   172→  reason: string;
   173→}
   174→
   175→/**
   176→ * AI Routing stage results
   177→ * Implements routing decisions per SCORING_LOGIC.md
   178→ */
   179→export interface AIRoutingResult {
   180→  routingDecision: 'skipAi' | 'featureExtraction' | 'fullClassification';
   181→  highConfidenceThreshold: number;
   182→  aiRequiredThreshold: number;
   183→  skipConditions: string[];
   184→  aiResponse?: {
   185→    extractedFeatures?: object;
   186→    suggestedCategories?: string[];
   187→    confidence: number;
   188→    reasoning: string;
   189→  };
   190→  reason: string;
   191→}
   192→
   193→/**
   194→ * Complete explainability trace structure per SCORING_LOGIC.md
   195→ * This preserves the sophisticated classification logic while
