    40→  includePerformanceMetrics: z.boolean().default(true),
    41→  includeConfigurationRefs: z.boolean().default(true),
    42→  serializationFormat: z.enum(['json', 'jsonb']).default('json'),
    43→});
    44→
    45→// Configuration interface for audit trail generation
    46→export interface AuditTrailConfig {
    47→  includePerformanceMetrics: boolean;
    48→  includeConfigurationRefs: boolean;
    49→  serializationFormat: 'json' | 'jsonb';
    50→}
    51→
    52→// Pipeline results interface aggregating all stage outputs
    53→export interface PipelineResults {
    54→  hardAssertions: HardAssertionsStageResult;
    55→  strongIndicators: StrongIndicatorsStageResult;
    56→  ruleScoring: RuleScoringStageResult;
    57→  attributeDetection: AttributeDetectionStageResult;
    58→  attributeInfluence: AttributeInfluenceStageResult;
    59→  disambiguation: DisambiguationStageResult;
    60→  multiLabelSelection: MultiLabelSelectionResult;
    61→  aiRouting: AIRoutingStageResult;
    62→  aiLabelFiltering: AILabelFilteringResult;
    63→  actionDetermination: ActionDeterminationStageResult;
    64→}
    65→
    66→// Action determination result for pipeline aggregation
    67→export interface ActionDeterminationStageResult {
    68→  determinedActions: string[];
    69→  actionReasoning: string;
    70→  processingDurationMs: number;
    71→}
    72→
    73→// Individual stage result interfaces (for audit trail aggregation purposes)
    74→export interface HardAssertionsStageResult {
    75→  appliedAssertions: HardAssertionResult[];
    76→  processingDurationMs: number;
    77→}
    78→
    79→export interface StrongIndicatorsStageResult {
    80→  appliedIndicators: StrongIndicatorResult[];
    81→  processingDurationMs: number;
    82→}
    83→
    84→export interface RuleScoringStageResult {
    85→  categoryScores: Record<string, number>;
    86→  subtypeScores: Record<string, Record<string, number>>;
    87→  ruleMatches?: RuleEvaluationResult[];
    88→  processingDurationMs: number;
    89→}
    90→
    91→export interface AttributeDetectionStageResult {
    92→  detectedAttributes: AttributeDetectionResult[];
    93→  processingDurationMs: number;
    94→}
    95→
    96→export interface AttributeInfluenceStageResult {
    97→  appliedInfluences: AttributeInfluenceResult[];
    98→  processingDurationMs: number;
    99→}
   100→
   101→export interface DisambiguationStageResult {
   102→  adjustments: DisambiguationResult[];
   103→  processingDurationMs: number;
   104→}
   105→
   106→export interface AIRoutingStageResult {
   107→  routingDecision: 'skipAi' | 'featureExtraction' | 'fullClassification';
   108→  highConfidenceThreshold: number;
   109→  aiRequiredThreshold: number;
   110→  skipConditions: string[];
   111→  aiResponse?: {
   112→    extractedFeatures?: object;
   113→    suggestedCategories?: string[];
   114→    confidence: number;
   115→    reasoning: string;
   116→  };
   117→  reason: string;
   118→  processingDurationMs: number;
   119→}
   120→
   121→// Complete audit trail result
   122→export interface AuditTrailResult {
   123→  sessionId: string;
   124→  emailId: string;
   125→  explainabilityTrace: ExplainabilityTrace;
   126→  processingDurationMs: number;
   127→}
   128→
   129→/**
   130→ * Generate Audit Trail
   131→ *
   132→ * Consolidates results from all 9 pipeline stages into a complete explainability trace
   133→ * for database persistence and debugging purposes.
   134→ *
   135→ * @param email - Email message being classified
   136→ * @param session - Classification session metadata
   137→ * @param pipelineResults - Results from all 9 pipeline stages
   138→ * @param config - Audit trail configuration
   139→ * @returns Complete audit trail with explainability trace
   140→ */
   141→export function generateAuditTrail(
   142→  email: EmailMessage,
   143→  session: ClassificationSession,
   144→  pipelineResults: PipelineResults,
   145→  config: AuditTrailConfig
   146→): AuditTrailResult {
   147→  const startTime = Date.now();
   148→
   149→  // Validate inputs
   150→  validateInputs(email, session, pipelineResults);
   151→
   152→  // Extract session and email IDs (support both id and legacy _id formats)
   153→  const sessionId = session.id || ((session as unknown as Record<string, unknown>).sessionId as string);
   154→  const emailId = email.id || ((email as unknown as Record<string, unknown>).gmailId as string);
   155→
   156→  // Aggregate stage timings
   157→  const stageTimings = aggregateStageTimings(pipelineResults);
   158→
   159→  // Build parallel execution map
   160→  const parallelExecutionMap = buildParallelExecutionMap(pipelineResults);
   161→
   162→  // Collect configuration references
   163→  const configurationRefs = config.includeConfigurationRefs ? collectConfigurationReferences(pipelineResults) : {};
   164→
   165→  // Generate final decision reason
   166→  const finalDecisionReason = generateFinalDecisionReason(pipelineResults);
   167→
   168→  // Extract alternative categories
   169→  const alternativeCategories = extractAlternativeCategories(pipelineResults);
   170→
   171→  // Convert multi-label selection results to explainability format
   172→  const multiLabelResults = convertMultiLabelResults(pipelineResults.multiLabelSelection);
   173→
   174→  // Convert rule scoring results to category rule results
   175→  const ruleScoringResults = convertRuleScoringResults(
   176→    pipelineResults.ruleScoring.ruleMatches,
   177→    pipelineResults.ruleScoring.categoryScores,
   178→    pipelineResults.ruleScoring.subtypeScores
   179→  );
   180→
   181→  // Build AI routing result
   182→  const aiRoutingResult = buildAIRoutingResult(pipelineResults.aiRouting);
   183→
   184→  // Construct complete explainability trace
   185→  const explainabilityTrace: ExplainabilityTrace = {
   186→    sessionId,
   187→    emailId,
   188→    hardAssertions: pipelineResults.hardAssertions.appliedAssertions,
   189→    strongIndicators: pipelineResults.strongIndicators.appliedIndicators,
   190→    ruleScoring: ruleScoringResults,
   191→    attributeDetection: pipelineResults.attributeDetection.detectedAttributes,
   192→    attributeInfluence: pipelineResults.attributeInfluence.appliedInfluences,
   193→    disambiguation: pipelineResults.disambiguation.adjustments,
   194→    multiLabelSelection: multiLabelResults,
   195→    aiRouting: aiRoutingResult,
   196→    stageTimings,
   197→    parallelExecutionMap,
   198→    configurationRefs,
   199→    finalDecisionReason,
   200→    alternativeCategories,
   201→  };
   202→
   203→  return {
   204→    sessionId,
   205→    emailId,
   206→    explainabilityTrace,
   207→    processingDurationMs: Date.now() - startTime,
   208→  };
   209→}
   210→
   211→/**
   212→ * Validate input parameters
   213→ */
   214→function validateInputs(email: EmailMessage, session: ClassificationSession, pipelineResults: PipelineResults): void {
   215→  validateEmailInput(email);
   216→  validateSessionInput(session);
   217→
   218→  if (!pipelineResults || typeof pipelineResults !== 'object') {
   219→    throw new Error('Invalid pipeline results: object required');
   220→  }
   221→
   222→  // Validate required stages
   223→  const requiredStages = [
   224→    'hardAssertions',
   225→    'strongIndicators',
   226→    'ruleScoring',
   227→    'attributeDetection',
   228→    'attributeInfluence',
   229→    'disambiguation',
   230→    'multiLabelSelection',
   231→    'aiRouting',
   232→    'aiLabelFiltering',
   233→  ];
   234→
   235→  for (const stage of requiredStages) {
   236→    if (!pipelineResults[stage as keyof PipelineResults]) {
   237→      throw new Error(`Missing required pipeline stage: ${stage}`);
   238→    }
   239→  }
   240→}
   241→
   242→/**
   243→ * Aggregate stage timings from all pipeline stages
   244→ */
   245→function aggregateStageTimings(pipelineResults: PipelineResults): Record<string, number> {
   246→  return {
   247→    hardAssertions: pipelineResults.hardAssertions.processingDurationMs,
   248→    strongIndicators: pipelineResults.strongIndicators.processingDurationMs,
   249→    ruleScoring: pipelineResults.ruleScoring.processingDurationMs,
   250→    attributeDetection: pipelineResults.attributeDetection.processingDurationMs,
   251→    attributeInfluence: pipelineResults.attributeInfluence.processingDurationMs,
   252→    disambiguation: pipelineResults.disambiguation.processingDurationMs,
   253→    multiLabelSelection: pipelineResults.multiLabelSelection.processingDurationMs,
   254→    aiRouting: pipelineResults.aiRouting.processingDurationMs,
   255→    aiLabelFiltering: pipelineResults.aiLabelFiltering.processingDurationMs,
   256→  };
   257→}
   258→
   259→/**
   260→ * Build parallel execution map tracking which stages/attributes ran concurrently
   261→ */
   262→function buildParallelExecutionMap(pipelineResults: PipelineResults): Record<string, string[]> {
   263→  const parallelMap: Record<string, string[]> = {};
   264→
   265→  // Track parallel-processed attributes from attribute detection stage
   266→  const parallelAttributes = pipelineResults.attributeDetection.detectedAttributes
   267→    .filter((attr) => attr.parallelProcessed)
   268→    .map((attr) => attr.attribute);
   269→
   270→  if (parallelAttributes.length > 0) {
   271→    parallelMap.attributeDetection = parallelAttributes;
   272→  }
   273→
   274→  return parallelMap;
   275→}
   276→
   277→/**
   278→ * Collect configuration references used throughout the pipeline
   279→ */
   280→function collectConfigurationReferences(pipelineResults: PipelineResults): Record<string, string> {
   281→  const refs: Record<string, string> = {};
   282→
   283→  // Hard assertions config
   284→  if (pipelineResults.hardAssertions.appliedAssertions.length > 0) {
   285→    refs.hardAssertions = 'config.processingConfig.categorySignals.*.hardAssertions';
   286→  }
   287→
   288→  // Strong indicators config
   289→  if (pipelineResults.strongIndicators.appliedIndicators.length > 0) {
   290→    refs.strongIndicators = 'config.processingConfig.categorySignals.*.strongIndicators';
   291→  }
   292→
   293→  // Rule scoring config
   294→  if (Object.keys(pipelineResults.ruleScoring.categoryScores).length > 0) {
   295→    refs.ruleScoring = 'config.processingConfig.topLevelCategories.*.subtypes.*.ruleBasedClassification';
   296→  }
   297→
   298→  // Attribute detection config
   299→  if (pipelineResults.attributeDetection.detectedAttributes.length > 0) {
   300→    refs.attributeDetection = 'config.processingConfig.attributes.detectors';
   301→  }
   302→
   303→  // Attribute influence config
   304→  if (pipelineResults.attributeInfluence.appliedInfluences.length > 0) {
   305→    refs.attributeInfluence = 'config.processingConfig.attributeRelevance';
   306→  }
   307→
   308→  // Disambiguation config
   309→  if (pipelineResults.disambiguation.adjustments.length > 0) {
   310→    refs.disambiguation = 'config.processingConfig.settings.disambiguation.confidenceGapThreshold';
   311→  }
   312→
   313→  // Multi-label selection config
   314→  refs.multiLabelSelection = 'config.processingConfig.multiLabelPolicy';
   315→
   316→  // AI routing config
   317→  refs.aiRouting = 'config.processingConfig.confidenceThresholds';
   318→
   319→  // AI label filtering config
   320→  refs.aiLabelFiltering = 'config.processingConfig.multiLabelPolicy';
   321→
   322→  return refs;
   323→}
   324→
   325→/**
   326→ * Generate final decision reason summarizing the complete classification pipeline
   327→ */
   328→function generateFinalDecisionReason(pipelineResults: PipelineResults): string {
   329→  const reasons: string[] = [];
   330→
   331→  // Check for hard assertions (highest priority)
   332→  if (pipelineResults.hardAssertions.appliedAssertions.length > 0) {
   333→    const categories = pipelineResults.hardAssertions.appliedAssertions.map((a) => a.category);
   334→    reasons.push(`Hard assertion matched for categories: ${Array.from(new Set(categories)).join(', ')}`);
   335→  }
   336→
   337→  // Check for strong indicators
   338→  if (pipelineResults.strongIndicators.appliedIndicators.length > 0) {
   339→    const categories = pipelineResults.strongIndicators.appliedIndicators.map((i) => i.category);
   340→    reasons.push(`Strong indicators detected for: ${Array.from(new Set(categories)).join(', ')}`);
   341→  }
   342→
   343→  // Include rule scoring results
   344→  const topCategories = Object.entries(pipelineResults.ruleScoring.categoryScores)
   345→    .sort((a, b) => b[1] - a[1])
   346→    .slice(0, 3);
   347→
   348→  if (topCategories.length > 0) {
   349→    const categoryScores = topCategories.map(([cat, score]) => `${cat}:${score.toFixed(1)}`).join(', ');
   350→    reasons.push(`Top rule-based scores: ${categoryScores}`);
   351→  }
   352→
   353→  // Include attribute influences
   354→  if (pipelineResults.attributeInfluence.appliedInfluences.length > 0) {
   355→    const attributeCount = pipelineResults.attributeInfluence.appliedInfluences.length;
   356→    reasons.push(`${attributeCount} attribute bonuses applied`);
   357→  }
   358→
   359→  // Include AI routing decision
   360→  if (pipelineResults.aiRouting.routingDecision !== 'skipAi') {
   361→    reasons.push(`AI classification used: ${pipelineResults.aiRouting.reason}`);
   362→  }
   363→
   364→  // Include AI label filtering (if AI was used)
   365→  const aiFilteringLabels = pipelineResults.aiLabelFiltering.assignedLabels;
   366→  reasons.push(
   367→    `Final assignment: primary=${aiFilteringLabels.primary}, secondary=[${aiFilteringLabels.secondary.join(', ')}]`
   368→  );
   369→
   370→  // Include action determination (applies to all emails)
   371→  if (pipelineResults.actionDetermination.determinedActions.length > 0) {
   372→    reasons.push(`Actions: ${pipelineResults.actionDetermination.determinedActions.join(', ')}`);
   373→  }
   374→
   375→  return reasons.join('; ');
   376→}
   377→
   378→/**
   379→ * Extract alternative categories that were not selected
   380→ */
   381→function extractAlternativeCategories(pipelineResults: PipelineResults): Array<{
   382→  category: string;
   383→  score: number;
   384→  eliminationReason: string;
   385→}> {
   386→  const alternatives: Array<{
   387→    category: string;
   388→    score: number;
   389→    eliminationReason: string;
   390→  }> = [];
   391→
   392→  const finalPrimary = pipelineResults.aiLabelFiltering.assignedLabels.primary;
   393→  const finalSecondary = pipelineResults.aiLabelFiltering.assignedLabels.secondary;
   394→  const selectedCategories = [finalPrimary, ...finalSecondary];
   395→
   396→  // Get all categories from rule scoring
   397→  const allCategories = Object.entries(pipelineResults.ruleScoring.categoryScores);
   398→
   399→  for (const [category, score] of allCategories) {
   400→    if (!selectedCategories.includes(category)) {
   401→      let eliminationReason = 'Score below selection threshold';
   402→
   403→      // Check if filtered by AI label filtering
   404→      const filteredLabels = pipelineResults.aiLabelFiltering.explainabilityTrace.filteredLabels || [];
   405→      const wasFiltered = filteredLabels.find((f) => f.category === category);
   406→      if (wasFiltered) {
   407→        eliminationReason = wasFiltered.filterReason;
   408→      }
   409→
   410→      alternatives.push({
   411→        category,
   412→        score,
   413→        eliminationReason,
   414→      });
   415→    }
   416→  }
   417→
   418→  // Sort by score descending
   419→  alternatives.sort((a, b) => b.score - a.score);
   420→
   421→  return alternatives;
   422→}
   423→
   424→/**
   425→ * Convert rule evaluation results to category rule results for explainability trace
   426→ */
   427→function convertRuleScoringResults(
   428→  ruleEvaluations: RuleEvaluationResult[] | undefined,
   429→  categoryScores: Record<string, number>,
   430→  _subtypeScores: Record<string, Record<string, number>>
   431→): CategoryRuleResult[] {
   432→  if (!ruleEvaluations || ruleEvaluations.length === 0) {
   433→    return [];
   434→  }
   435→
   436→  // Group rule evaluations by category
   437→  const categoryGroups = new Map<string, RuleEvaluationResult[]>();
   438→  for (const evaluation of ruleEvaluations) {
   439→    const existing = categoryGroups.get(evaluation.category) || [];
   440→    existing.push(evaluation);
   441→    categoryGroups.set(evaluation.category, existing);
   442→  }
   443→
   444→  // Convert each category group to CategoryRuleResult
   445→  const categoryResults: CategoryRuleResult[] = [];
   446→  for (const [categoryCode, evaluations] of Array.from(categoryGroups.entries())) {
   447→    // Aggregate all rule matches across subtypes
   448→    const allRuleMatches: RuleScoringMatch[] = [];
   449→    const subtypeScoresMap: Record<string, SubtypeScore> = {};
   450→
   451→    for (const evaluation of evaluations) {
   452→      // Convert RuleMatch[] to RuleScoringMatch[]
   453→      const scoringMatches: RuleScoringMatch[] = evaluation.matchedRules.map((match) => ({
   454→        ...match,
   455→        tier: (evaluation.tier === 'high'
   456→          ? 'highConfidence'
   457→          : evaluation.tier === 'medium'
   458→            ? 'mediumConfidence'
   459→            : 'lowConfidence') as 'highConfidence' | 'mediumConfidence' | 'lowConfidence',
   460→        values: [match.matchedValue],
   461→        weight: match.ruleWeight,
   462→        ruleId: `${evaluation.category}_${evaluation.subtype}_${match.field}`,
   463→      }));
   464→
   465→      allRuleMatches.push(...scoringMatches);
   466→
   467→      // Build subtype score entry
   468→      subtypeScoresMap[evaluation.subtype] = {
   469→        totalScore: evaluation.cappedScore,
   470→        ruleMatches: scoringMatches,
   471→        aggregationBreakdown: evaluation.reason,
   472→      };
   473→    }
   474→
   475→    // Find the subtype with highest score
   476→    const subtypeEntries = Object.entries(subtypeScoresMap);
   477→    const selectedSubtype =
   478→      subtypeEntries.length > 0
   479→        ? subtypeEntries.reduce(
   480→            (max, [id, score]) => (score.totalScore > max.score ? { id, score: score.totalScore } : max),
   481→            { id: subtypeEntries[0][0], score: subtypeEntries[0][1].totalScore }
   482→          )
   483→        : null;
   484→
   485→    // Get category aggregated score from categoryScores
   486→    const aggregatedScore = categoryScores[categoryCode] || 0;
   487→
   488→    // Build scoring rationale
   489→    const scoringRationale = evaluations.map((e) => e.reason);
   490→
   491→    categoryResults.push({
   492→      categoryCode,
   493→      aggregatedScore,
   494→      subtypeScores: subtypeScoresMap,
   495→      ruleMatches: allRuleMatches,
   496→      scoringRationale,
   497→      selectedSubtypeId: selectedSubtype?.id || null,
   498→      confidence: aggregatedScore / 100, // Convert score to confidence (0-1 range)
   499→    });
   500→  }
   501→
   502→  return categoryResults;
   503→}
   504→
   505→/**
   506→ * Convert multi-label selection results to explainability format
   507→ */
   508→function convertMultiLabelResults(multiLabelResult: MultiLabelSelectionResult): ExplainMultiLabelResult[] {
   509→  return multiLabelResult.selectedLabels.map((label) => ({
   510→    selectedCategories: [label.category],
   511→    rejectedCategories: [],
   512→    coPresenceRulesApplied: [],
   513→    maxLabelsLimit: 1,
   514→    minSecondaryConfidence: 0,
   515→    reason: label.selectionRationale,
   516→  }));
   517→}
   518→
   519→/**
   520→ * Build AI routing result for explainability trace
   521→ */
   522→function buildAIRoutingResult(aiRoutingResult: AIRoutingStageResult): AIRoutingResult | undefined {
   523→  // AI routing is optional - only include if AI was actually used
   524→  if (aiRoutingResult.routingDecision === 'skipAi' && !aiRoutingResult.aiResponse) {
   525→    return {
   526→      routingDecision: aiRoutingResult.routingDecision,
   527→      highConfidenceThreshold: aiRoutingResult.highConfidenceThreshold,
   528→      aiRequiredThreshold: aiRoutingResult.aiRequiredThreshold,
   529→      skipConditions: aiRoutingResult.skipConditions,
   530→      reason: aiRoutingResult.reason,
   531→    };
   532→  }
   533→
   534→  return {
   535→    routingDecision: aiRoutingResult.routingDecision,
   536→    highConfidenceThreshold: aiRoutingResult.highConfidenceThreshold,
   537→    aiRequiredThreshold: aiRoutingResult.aiRequiredThreshold,
   538→    skipConditions: aiRoutingResult.skipConditions,
   539→    aiResponse: aiRoutingResult.aiResponse,
   540→    reason: aiRoutingResult.reason,
   541→  };
   542→}
   543→

