   231→        data: signals.map((signal) => ({
   232→          sessionId: dbSessionId,
   233→          domain: signal.domain,
   234→          signalType: signal.signalType,
   235→          matchedCategoryId: signal.matchedCategoryId,
   236→          confidenceLevel: signal.confidenceLevel || null,
   237→          domainType: signal.domainType || null,
   238→          createdAt: new Date(),
   239→        })),
   240→      });
   241→    } catch (error) {
   242→      throw new Error(`Failed to save domain signals: ${error instanceof Error ? error.message : String(error)}`);
   243→    }
   244→  }
   245→
   246→  /**
   247→   * Batch save multiple classification results
   248→   *
   249→   * @param results - Array of ClassificationResult objects
   250→   * @param sessionId - Session identifier as string (from createSession)
   251→   * @throws {Error} If batch save fails
   252→   */
   253→  async batchSaveResults(results: ClassificationResult[], sessionId: string): Promise<void> {
   254→    if (results.length === 0) {
   255→      return;
   256→    }
   257→
   258→    try {
   259→      // Save each result sequentially within a transaction
   260→      for (const result of results) {
   261→        await this.saveClassificationResult(result, sessionId);
   262→      }
   263→    } catch (error) {
   264→      throw new Error(
   265→        `Failed to batch save classification results: ${error instanceof Error ? error.message : String(error)}`
   266→      );
   267→    }
   268→  }
   269→
   270→  /**
   271→   * Build classification stage data from explainability trace
   272→   */
   273→  private buildStageData(
   274→    result: ClassificationResult,
   275→    sessionId: bigint
   276→  ): Array<Prisma.ClassificationStageCreateManyInput> {
   277→    const stages: Array<Prisma.ClassificationStageCreateManyInput> = [];
   278→    const trace = result.explainabilityTrace;
   279→
   280→    // Map pipeline stages to database records
   281→    const stageMapping = [
   282→      { order: 1, type: 'hard_assertions', data: trace.hardAssertions },
   283→      { order: 2, type: 'strong_indicators', data: trace.strongIndicators },
   284→      { order: 3, type: 'rule_scoring', data: trace.ruleScoring },
   285→      { order: 4, type: 'attribute_detection', data: trace.attributeDetection },
   286→      { order: 5, type: 'attribute_influence', data: trace.attributeInfluence },
   287→      { order: 6, type: 'disambiguation', data: trace.disambiguation },
   288→      { order: 7, type: 'multi_label_selection', data: trace.multiLabelSelection },
   289→      { order: 8, type: 'ai_routing', data: trace.aiRouting },
   290→      { order: 9, type: 'final_decision', data: { reason: trace.finalDecisionReason } },
   291→      {
   292→        order: 10,
   293→        type: 'action_determination',
   294→        data: {
   295→          determinedActions: result.determinedActions || [],
   296→          actionReasoning: result.finalClassificationSummary?.determinedActions
   297→            ? `Actions: ${result.finalClassificationSummary.determinedActions.join(', ')}`
   298→            : 'No actions determined',
   299→        },
   300→      },
   301→    ];
   302→
   303→    for (const stage of stageMapping) {
   304→      stages.push({
   305→        sessionId: sessionId,
   306→        stageOrder: stage.order,
   307→        stageType: stage.type,
   308→        startedAt: new Date(),
   309→        endedAt: new Date(),
   310→        features: stage.data as Prisma.InputJsonValue,
   311→        keywords: [],
   312→        passedToNext: true,
   313→      });
   314→    }
   315→
   316→    return stages;
   317→  }
   318→
   319→  /**
   320→   * Build stage category evaluation data from score breakdown
   321→   */
   322→  private buildCategoryEvalData(
   323→    result: ClassificationResult,
   324→    sessionId: bigint
   325→  ): Array<Prisma.StageCategoryEvalCreateManyInput> {
   326→    const evaluations: Array<Prisma.StageCategoryEvalCreateManyInput> = [];
   327→    const scoreBreakdown = result.scoreBreakdown;
   328→
   329→    // Extract category scores and create evaluations
   330→    for (const [category, scores] of Object.entries(scoreBreakdown.categoryScores || {})) {
   331→      evaluations.push({
   332→        stageId: sessionId, // Simplified: using session_id as stage_id for MVP
   333→        categoryId: this.getCategoryIdFromCode(category),
   334→        decision: result.selectedLabels.some((label) => label.category === category) ? 'positive' : 'candidate',
   335→        score: scores as unknown as Prisma.InputJsonValue,
   336→        confidence: new Prisma.Decimal(scores.finalScore || 0),
   337→        scoringComponents: scores as unknown as Prisma.InputJsonValue,
   338→        keywords: [],
   339→        createdAt: new Date(),
   340→      });
   341→    }
   342→
   343→    return evaluations;
   344→  }
   345→
   346→  /**
   347→   * Build session category data (multi-label support)
   348→   */
   349→  private buildSessionCategoryData(
   350→    result: ClassificationResult,
   351→    sessionId: bigint
   352→  ): Array<Prisma.SessionCategoryCreateManyInput> {
   353→    const categories: Array<Prisma.SessionCategoryCreateManyInput> = [];
   354→
   355→    for (const label of result.selectedLabels) {
   356→      categories.push({
   357→        sessionId: sessionId,
   358→        categoryId: this.getCategoryIdFromCode(label.category),
   359→        subtypeId: label.subtype ? this.getCategoryIdFromCode(label.subtype) : null,
   360→        isPrimary: label.isPrimary,
   361→        confidence: new Prisma.Decimal(label.confidence),
   362→        categoryScore: new Prisma.Decimal(label.score),
   363→        hardAssertion: false, // TODO: Extract from explainability trace
   364→        aiClassified: result.aiRoutingUsed,
   365→        scoringTrace: result.scoreBreakdown as unknown as Prisma.InputJsonValue,
   366→        labelOrder: label.labelOrder,
   367→        createdAt: new Date(),
   368→      });
   369→    }
   370→
   371→    return categories;
   372→  }
   373→
   374→  /**
   375→   * Build detected attribute data from attribute context
   376→   */
   377→  private buildAttributeData(
   378→    context: AttributeContext,
   379→    sessionId: bigint
   380→  ): Array<Prisma.DetectedAttributeCreateManyInput> {
   381→    const attributes: Array<Prisma.DetectedAttributeCreateManyInput> = [];
   382→
   383→    // Add urgency attribute
   384→    attributes.push({
   385→      sessionId: sessionId,
   386→      attributeName: 'urgency',
   387→      attributeValue: context.urgency,
   388→      detectionMethod: 'rule',
   389→      detectionEvidence: 'Urgency level detection',
   390→      influenceRole: 'FILTER',
   391→      categoriesInfluenced: [],
   392→      totalBonusApplied: new Prisma.Decimal(0),
   393→      createdAt: new Date(),
   394→    });
   395→
   396→    // Add domain attributes
   397→    for (const domain of context.domains) {
   398→      attributes.push({
   399→        sessionId: sessionId,
   400→        attributeName: `domain:${domain}`,
   401→        attributeValue: domain,
   402→        detectionMethod: 'domain_lookup',
   403→        detectionEvidence: `Domain ${domain} detected`,
   404→        influenceRole: 'CORE',
   405→        categoriesInfluenced: [],
   406→        totalBonusApplied: new Prisma.Decimal(0),
   407→        createdAt: new Date(),
   408→      });
   409→    }
   410→
   411→    // Add structural pattern attributes
   412→    for (const pattern of context.structuralPatterns) {
   413→      attributes.push({
   414→        sessionId: sessionId,
   415→        attributeName: `pattern:${pattern}`,
   416→        attributeValue: pattern,
   417→        detectionMethod: 'regex',
   418→        detectionEvidence: `Pattern ${pattern} matched`,
   419→        influenceRole: 'SECONDARY_BOOST',
   420→        categoriesInfluenced: [],
   421→        totalBonusApplied: new Prisma.Decimal(0),
   422→        createdAt: new Date(),
   423→      });
   424→    }
   425→
   426→    return attributes;
   427→  }
   428→
   429→  /**
   430→   * Get category ID from category code
   431→   *
   432→   * Uses cached category lookup for performance. Cache is initialized
   433→   * on first use and persists for the lifetime of the repository instance.
   434→   *
   435→   * @param code - Category code (e.g., 'finance', 'personal')
   436→   * @returns Category ID from database
   437→   * @throws {Error} If category code not found in database
   438→   */
   439→  private async getCategoryIdFromCode(code: string): Promise<number> {
   440→    // Initialize cache on first use
   441→    if (this.categoryCache === null) {
   442→      await this.initializeCategoryCache();
   443→    }
   444→
   445→    const categoryId = this.categoryCache!.get(code);
   446→    if (categoryId === undefined) {
   447→      throw new Error(
   448→        `Category code '${code}' not found in database. Available categories: ${Array.from(this.categoryCache!.keys()).join(', ')}`
   449→      );
   450→    }
   451→
   452→    return categoryId;
   453→  }
   454→
   455→  /**
   456→   * Close the Prisma client connection
   457→   *
   458→   * Only closes if using default Prisma instance (not externally provided).
   459→   */
   460→  async close(): Promise<void> {
   461→    if (this.ownsPrisma) {
   462→      await this.prisma.$disconnect();
   463→    }
   464→  }
   465→}
