      await expect(repository.batchSaveResults(results, '1')).rejects.toThrow(
        'Failed to batch save classification results'
      );
    });
  });

  describe('Constructor and Cleanup', () => {
    it('should create repository with default Prisma client', () => {
      const repo = new ClassificationRepository();
      expect(repo).toBeInstanceOf(ClassificationRepository);
    });

    it('should create repository with provided Prisma client', () => {
      const externalPrisma = new PrismaClient();
      const repo = new ClassificationRepository(externalPrisma);
      expect(repo).toBeInstanceOf(ClassificationRepository);
    });

    it('should close repository and disconnect Prisma', async () => {
      const repo = new ClassificationRepository();
      await repo.close();

      expect(mockPrisma.$disconnect).toHaveBeenCalled();
    });

    it('should not disconnect externally provided Prisma client', async () => {
      const externalPrisma = new PrismaClient();
      const repo = new ClassificationRepository(externalPrisma);
      await repo.close();

      // Should not disconnect external client
      expect(mockPrisma.$disconnect).not.toHaveBeenCalled();
    });
  });
});

