     1→/**
     2→ * Classification Results Persistence Layer (T043) - Prisma Implementation
     3→ *
     4→ * Repository pattern for classification results persistence using Prisma ORM:
     5→ * - Classification session management (create, update, complete)
     6→ * - Classification results with explainability traces
     7→ * - Score breakdown persistence
     8→ * - Attribute context storage
     9→ * - Multi-label classification support
    10→ * - Domain signal resolutions
    11→ * - Transaction-safe batch operations
    12→ *
    13→ * Benefits of Prisma ORM:
    14→ * - Type-safe database queries with auto-generated types
    15→ * - Built-in transaction handling for complex multi-table operations
    16→ * - Automatic JSON serialization/deserialization for explainability data
    17→ * - Connection pooling and query optimization
    18→ * - SQL injection protection via parameterized queries
    19→ */
    20→
    21→import { PrismaClient, Prisma } from '@prisma/client';
    22→import { ClassificationResult, ClassificationSession, AttributeContext } from '@gmail-automation/classification-engine';
    23→
    24→/**
    25→ * Domain signal resolution data structure
    26→ */
    27→export interface DomainSignalData {
    28→  domain: string;
    29→  signalType: 'hard_assertion' | 'strong_indicator' | 'weak_signal';
    30→  matchedCategoryId: number | null;
    31→  confidenceLevel?: string;
    32→  domainType?: string;
    33→}
    34→
    35→/**
    36→ * Classification Repository using Prisma ORM
    37→ *
    38→ * Provides type-safe classification results persistence with automatic transaction
    39→ * handling, connection pooling, and explainability trace integrity.
    40→ */
    41→export class ClassificationRepository {
    42→  private readonly prisma: PrismaClient;
    43→  private readonly ownsPrisma: boolean;
    44→
    45→  /**
    46→   * Initialize classification repository
    47→   *
    48→   * @param prisma - Optional Prisma client instance (creates default if not provided)
    49→   */
    50→  constructor(prisma?: PrismaClient) {
    51→    if (prisma) {
    52→      this.prisma = prisma;
    53→      this.ownsPrisma = false;
    54→    } else {
    55→      this.prisma = new PrismaClient();
    56→      this.ownsPrisma = true;
    57→    }
    58→  }
    59→
    60→  /**
    61→   * Create a new classification session
    62→   *
    63→   * @param session - ClassificationSession object
    64→   * @param gmailId - Gmail message ID being classified
    65→   * @returns Database session ID as string (safe representation of bigint)
    66→   * @throws {Error} If session creation fails
    67→   */
    68→  async createSession(session: ClassificationSession, gmailId: string): Promise<string> {
    69→    try {
    70→      const result = await this.prisma.classificationSession.create({
    71→        data: {
    72→          gmailId: gmailId,
    73→          pipelineVersion: session.configVersion,
    74→          startedAt: session.startedAt,
    75→          status: 'in_progress',
    76→          triggeredBy: 'system',
    77→          aiRoutingUsed: false,
    78→        },
    79→      });
    80→
    81→      return result.sessionId.toString();
    82→    } catch (error) {
    83→      throw new Error(
    84→        `Failed to create classification session: ${error instanceof Error ? error.message : String(error)}`
    85→      );
    86→    }
    87→  }
    88→
    89→  /**
    90→   * Complete a classification session
    91→   *
    92→   * @param sessionId - Session identifier as string (from createSession)
    93→   * @param finalCategoryId - Final category ID selected
    94→   * @param confidence - Final confidence score
    95→   * @param rationale - Final decision rationale
    96→   * @throws {Error} If session update fails
    97→   */
    98→  async completeSession(
    99→    sessionId: string,
   100→    finalCategoryId: number,
   101→    confidence: number,
   102→    rationale: string
   103→  ): Promise<void> {
   104→    try {
   105→      // Convert string session ID to BigInt for database query
   106→      const dbSessionId = BigInt(sessionId);
   107→
   108→      await this.prisma.classificationSession.update({
   109→        where: { sessionId: dbSessionId },
   110→        data: {
   111→          completedAt: new Date(),
   112→          finalCategoryId: finalCategoryId,
   113→          finalConfidence: new Prisma.Decimal(confidence),
   114→          finalRationale: rationale,
   115→          status: 'completed',
   116→        },
   117→      });
   118→    } catch (error) {
   119→      throw new Error(
   120→        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   121→      );
   122→    }
   123→  }
   124→
   125→  /**
   126→   * Save complete classification result with explainability trace
   127→   *
   128→   * Uses Prisma transaction to ensure atomicity across multiple tables:
   129→   * - classification_stage (9 pipeline stages)
   130→   * - stage_category_eval (per-category evaluations)
   131→   * - session_categories (multi-label support)
   132→   * - detected_attributes (attribute context)
   133→   * - domain_signal_resolutions (domain signals)
   134→   *
   135→   * @param result - ClassificationResult with explainability trace
   136→   * @param sessionId - Session identifier as string (from createSession)
   137→   * @throws {Error} If save fails (rolls back entire transaction)
   138→   */
   139→  async saveClassificationResult(result: ClassificationResult, sessionId: string): Promise<void> {
   140→    try {
   141→      const dbSessionId = BigInt(sessionId);
   142→
   143→      await this.prisma.$transaction(async (tx) => {
   144→        // 1. Create classification stages (9 pipeline stages: hard assertions through audit trail)
   145→        const stageData = this.buildStageData(result, dbSessionId);
   146→        if (stageData.length > 0) {
   147→          await tx.classificationStage.createMany({ data: stageData });
   148→        }
   149→
   150→        // 2. Create stage category evaluations (score breakdown for each category)
   151→        const categoryEvalData = this.buildCategoryEvalData(result, dbSessionId);
   152→        if (categoryEvalData.length > 0) {
   153→          await tx.stageCategoryEval.createMany({ data: categoryEvalData });
   154→        }
   155→
   156→        // 3. Create session categories (multi-label support)
   157→        const sessionCategoryData = this.buildSessionCategoryData(result, dbSessionId);
   158→        if (sessionCategoryData.length > 0) {
   159→          await tx.sessionCategory.createMany({ data: sessionCategoryData });
   160→        }
   161→
   162→        // 4. Create detected attributes (attribute context)
   163→        const attributeData = this.buildAttributeData(result.attributeContext, dbSessionId);
   164→        if (attributeData.length > 0) {
   165→          await tx.detectedAttribute.createMany({ data: attributeData });
   166→        }
   167→      });
   168→    } catch (error) {
   169→      throw new Error(
   170→        `Failed to save classification result for email ${result.emailId}: ${error instanceof Error ? error.message : String(error)}`
   171→      );
   172→    }
   173→  }
   174→
   175→  /**
   176→   * Save attribute context separately
   177→   *
   178→   * @param context - AttributeContext with detected attributes
   179→   * @param sessionId - Session identifier as string (from createSession)
   180→   * @throws {Error} If save fails
   181→   */
   182→  async saveAttributeContext(context: AttributeContext, sessionId: string): Promise<void> {
   183→    try {
   184→      const dbSessionId = BigInt(sessionId);
   185→      const attributeData = this.buildAttributeData(context, dbSessionId);
   186→      if (attributeData.length > 0) {
   187→        await this.prisma.detectedAttribute.createMany({ data: attributeData });
   188→      }
   189→    } catch (error) {
   190→      throw new Error(`Failed to save attribute context: ${error instanceof Error ? error.message : String(error)}`);
   191→    }
   192→  }
   193→
   194→  /**
   195→   * Save domain signal resolutions
   196→   *
   197→   * @param signals - Array of domain signal resolutions
   198→   * @param sessionId - Session identifier as string (from createSession)
   199→   * @throws {Error} If save fails
   200→   */
   201→  async saveDomainSignals(signals: DomainSignalData[], sessionId: string): Promise<void> {
   202→    if (signals.length === 0) {
   203→      return;
   204→    }
   205→
   206→    try {
   207→      const dbSessionId = BigInt(sessionId);
   208→      await this.prisma.domainSignalResolution.createMany({
   209→        data: signals.map((signal) => ({
   210→          sessionId: dbSessionId,
   211→          domain: signal.domain,
   212→          signalType: signal.signalType,
   213→          matchedCategoryId: signal.matchedCategoryId,
   214→          confidenceLevel: signal.confidenceLevel || null,
   215→          domainType: signal.domainType || null,
   216→          createdAt: new Date(),
   217→        })),
   218→      });
   219→    } catch (error) {
   220→      throw new Error(`Failed to save domain signals: ${error instanceof Error ? error.message : String(error)}`);
   221→    }
   222→  }
   223→
   224→  /**
   225→   * Batch save multiple classification results
   226→   *
   227→   * @param results - Array of ClassificationResult objects
   228→   * @param sessionId - Session identifier as string (from createSession)
   229→   * @throws {Error} If batch save fails
   230→   */
   231→  async batchSaveResults(results: ClassificationResult[], sessionId: string): Promise<void> {
   232→    if (results.length === 0) {
   233→      return;
   234→    }
   235→
   236→    try {
   237→      // Save each result sequentially within a transaction
   238→      for (const result of results) {
   239→        await this.saveClassificationResult(result, sessionId);
   240→      }
   241→    } catch (error) {
   242→      throw new Error(
   243→        `Failed to batch save classification results: ${error instanceof Error ? error.message : String(error)}`
   244→      );
   245→    }
   246→  }
   247→
   248→  /**
   249→   * Build classification stage data from explainability trace
   250→   */
   251→  private buildStageData(
   252→    result: ClassificationResult,
   253→    sessionId: bigint
   254→  ): Array<Prisma.ClassificationStageCreateManyInput> {
   255→    const stages: Array<Prisma.ClassificationStageCreateManyInput> = [];
   256→    const trace = result.explainabilityTrace;
   257→
   258→    // Map pipeline stages to database records
