   106→
   107→export interface ParallelStageResult {
   108→  stageId: string;
   109→  stageName: string;
   110→  executionTimeMs: number;
   111→  parallelWithStages: string[];
   112→  dependentOnStages: string[];
   113→  memoryUsageMB?: number;
