   116→}
   117→
   118→/**
   119→ * Classification confidence levels with business semantics
   120→ */
   121→export enum ConfidenceLevel {
   122→  HIGH = 'high', // > 0.8 - Can proceed without review
   123→  MEDIUM = 'medium', // 0.5 - 0.8 - May need review for important actions
