   126→}
   127→
   128→/**
   129→ * Category assignment types for multi-label support
   130→ */
   131→export enum CategoryAssignmentType {
   132→  PRIMARY = 'primary', // Main category assignment
   133→  SECONDARY = 'secondary', // Additional relevant category
