   391→        attributeValue: domain,
   392→        detectionMethod: 'domain_lookup',
   393→        detectionEvidence: `Domain ${domain} detected`,
   394→        influenceRole: 'CORE',
   395→        categoriesInfluenced: [],
   396→        totalBonusApplied: new Prisma.Decimal(0),
   397→        createdAt: new Date(),
   398→      });
   399→    }
   400→
   401→    // Add structural pattern attributes
   402→    for (const pattern of context.structuralPatterns) {
   403→      attributes.push({
   404→        sessionId: sessionId,
   405→        attributeName: `pattern:${pattern}`,
   406→        attributeValue: pattern,
   407→        detectionMethod: 'regex',
   408→        detectionEvidence: `Pattern ${pattern} matched`,
   409→        influenceRole: 'SECONDARY_BOOST',
   410→        categoriesInfluenced: [],
   411→        totalBonusApplied: new Prisma.Decimal(0),
   412→        createdAt: new Date(),
   413→      });
   414→    }
   415→
   416→    return attributes;
   417→  }
   418→
   419→  /**
   420→   * Get category ID from category code
   421→   *
   422→   * Uses cached category lookup for performance. Cache is initialized
   423→   * on first use and persists for the lifetime of the repository instance.
   424→   *
   425→   * @param code - Category code (e.g., 'finance', 'personal')
   426→   * @returns Category ID from database
   427→   * @throws {Error} If category code not found in database
   428→   */
   429→  private async getCategoryIdFromCode(code: string): Promise<number> {
   430→    // Initialize cache on first use
   431→    if (this.categoryCache === null) {
   432→      await this.initializeCategoryCache();
