   436→    if (categoryId === undefined) {
   437→      throw new Error(
   438→        `Category code '${code}' not found in database. Available categories: ${Array.from(this.categoryCache!.keys()).join(', ')}`
   439→      );
   440→    }
   441→
   442→    return categoryId;
   443→  }
   444→
   445→  /**
   446→   * Close the Prisma client connection
   447→   *
   448→   * Only closes if using default Prisma instance (not externally provided).
   449→   */
   450→  async close(): Promise<void> {
   451→    if (this.ownsPrisma) {
   452→      await this.prisma.$disconnect();
   453→    }
   454→  }
