   175→          await tx.stageCategoryEval.createMany({ data: categoryEvalData });
   176→        }
   177→
   178→        // 3. Create session categories (multi-label support)
   179→        const sessionCategoryData = await this.buildSessionCategoryData(result, dbSessionId);
   180→        if (sessionCategoryData.length > 0) {
   181→          await tx.sessionCategory.createMany({ data: sessionCategoryData });
   182→        }
   183→
   184→        // 4. Create detected attributes (attribute context)
   185→        const attributeData = this.buildAttributeData(result.attributeContext, dbSessionId);
   186→        if (attributeData.length > 0) {
   187→          await tx.detectedAttribute.createMany({ data: attributeData });
   188→        }
   189→      });
   190→    } catch (error) {
   191→      throw new Error(
   192→        `Failed to save classification result for email ${result.emailId}: ${error instanceof Error ? error.message : String(error)}`
   193→      );
   194→    }
   195→  }
   196→
   197→  /**
   198→   * Save attribute context separately
   199→   *
   200→   * @param context - AttributeContext with detected attributes
   201→   * @param sessionId - Session identifier as string (from createSession)
   202→   * @throws {Error} If save fails
   203→   */
   204→  async saveAttributeContext(context: AttributeContext, sessionId: string): Promise<void> {
   205→    try {
   206→      const dbSessionId = BigInt(sessionId);
   207→      const attributeData = this.buildAttributeData(context, dbSessionId);
   208→      if (attributeData.length > 0) {
   209→        await this.prisma.detectedAttribute.createMany({ data: attributeData });
   210→      }
   211→    } catch (error) {
   212→      throw new Error(`Failed to save attribute context: ${error instanceof Error ? error.message : String(error)}`);
   213→    }
   214→  }
   215→
   216→  /**
   217→   * Save domain signal resolutions
   218→   *
   219→   * @param signals - Array of domain signal resolutions
   220→   * @param sessionId - Session identifier as string (from createSession)
   221→   * @throws {Error} If save fails
   222→   */
   223→  async saveDomainSignals(signals: DomainSignalData[], sessionId: string): Promise<void> {
   224→    if (signals.length === 0) {
   225→      return;
   226→    }
   227→
   228→    try {
   229→      const dbSessionId = BigInt(sessionId);
   230→      await this.prisma.domainSignalResolution.createMany({
   231→        data: signals.map((signal) => ({
   232→          sessionId: dbSessionId,
