   242→      throw new Error(`Failed to save domain signals: ${error instanceof Error ? error.message : String(error)}`);
   243→    }
   244→  }
   245→
   246→  /**
   247→   * Batch save multiple classification results
   248→   *
   249→   * @param results - Array of ClassificationResult objects
   250→   * @param sessionId - Session identifier as string (from createSession)
   251→   * @throws {Error} If batch save fails
   252→   */
   253→  async batchSaveResults(results: ClassificationResult[], sessionId: string): Promise<void> {
   254→    if (results.length === 0) {
   255→      return;
   256→    }
   257→
   258→    try {
   259→      // Save each result sequentially within a transaction
