   263→    } catch (error) {
   264→      throw new Error(
   265→        `Failed to batch save classification results: ${error instanceof Error ? error.message : String(error)}`
   266→      );
   267→    }
   268→  }
   269→
   270→  /**
   271→   * Build classification stage data from explainability trace
   272→   */
   273→  private buildStageData(
   274→    result: ClassificationResult,
   275→    sessionId: bigint
   276→  ): Array<Prisma.ClassificationStageCreateManyInput> {
   277→    const stages: Array<Prisma.ClassificationStageCreateManyInput> = [];
   278→    const trace = result.explainabilityTrace;
   279→
   280→    // Map pipeline stages to database records
   281→    const stageMapping = [
   282→      { order: 1, type: 'hard_assertions', data: trace.hardAssertions },
   283→      { order: 2, type: 'strong_indicators', data: trace.strongIndicators },
   284→      { order: 3, type: 'rule_scoring', data: trace.ruleScoring },
   285→      { order: 4, type: 'attribute_detection', data: trace.attributeDetection },
   286→      { order: 5, type: 'attribute_influence', data: trace.attributeInfluence },
   287→      { order: 6, type: 'disambiguation', data: trace.disambiguation },
