   327→    const scoreBreakdown = result.scoreBreakdown;
   328→
   329→    // Extract category scores and create evaluations
   330→    for (const [category, scores] of Object.entries(scoreBreakdown.categoryScores || {})) {
   331→      try {
   332→        const categoryId = await this.getCategoryIdFromCode(category);
   333→        evaluations.push({
   334→          stageId: sessionId, // Simplified: using session_id as stage_id for MVP
   335→          categoryId: categoryId,
