   337→          score: scores as unknown as Prisma.InputJsonValue,
   338→          confidence: new Prisma.Decimal(scores.finalScore || 0),
   339→          scoringComponents: scores as unknown as Prisma.InputJsonValue,
   340→          keywords: [],
   341→          createdAt: new Date(),
   342→        });
   343→      } catch (error) {
   344→        // Log warning and skip unknown category (graceful degradation)
