   347→        );
   348→      }
   349→    }
   350→
   351→    return evaluations;
   352→  }
   353→
   354→  /**
   355→   * Build session category data (multi-label support)
   356→   */
   357→  private async buildSessionCategoryData(
   358→    result: ClassificationResult,
   359→    sessionId: bigint
   360→  ): Promise<Array<Prisma.SessionCategoryCreateManyInput>> {
   361→    const categories: Array<Prisma.SessionCategoryCreateManyInput> = [];
   362→
   363→    for (const label of result.selectedLabels) {
   364→      try {
   365→        const categoryId = await this.getCategoryIdFromCode(label.category);
   366→        const subtypeId = label.subtype ? await this.getCategoryIdFromCode(label.subtype) : null;
   367→
   368→        categories.push({
   369→          sessionId: sessionId,
   370→          categoryId: categoryId,
   371→          subtypeId: subtypeId,
   372→          isPrimary: label.isPrimary,
   373→          confidence: new Prisma.Decimal(label.confidence),
   374→          categoryScore: new Prisma.Decimal(label.score),
   375→          hardAssertion: false, // TODO: Extract from explainability trace
   376→          aiClassified: result.aiRoutingUsed,
   377→          scoringTrace: result.scoreBreakdown as unknown as Prisma.InputJsonValue,
   378→          labelOrder: label.labelOrder,
   379→          createdAt: new Date(),
   380→        });
   381→      } catch (error) {
   382→        // Log warning and skip unknown category (graceful degradation)
   383→        console.warn(
