/**
 * Save complete classification result with explainability trace
 *
 * Uses Prisma transaction to ensure atomicity across multiple tables:
 * - classification_stage (10 pipeline stages)
 * - stage_category_eval (per-category evaluations)
 * - session_categories (multi-label support)
 * - detected_attributes (attribute context)
 * - extracted_features (AI feature extraction data, if AI was used)
 * - domain_signal_resolutions (domain signals)
 *
 * @param result - ClassificationResult with explainability trace
 * @param sessionId - Session identifier as string (from createSession)
 * @throws {Error} If save fails (rolls back entire transaction)
 */
async saveClassificationResult(result: ClassificationResult, sessionId: string): Promise<void> {
  try {
    const dbSessionId = BigInt(sessionId);

    await this.prisma.$transaction(async (tx) => {
      // 1. Create classification stages (10 pipeline stages: hard assertions through action determination)
      const stageData = this.buildStageData(result, dbSessionId);
      let stageRecords: Array<{ stageId: bigint; stageOrder: number }> = [];
      if (stageData.length > 0) {
        await tx.classificationStage.createMany({ data: stageData });

        // Retrieve created stage records to get stage IDs for AI feature extraction
        stageRecords = await tx.classificationStage.findMany({
          where: { sessionId: dbSessionId },
          select: { stageId: true, stageOrder: true },
          orderBy: { stageOrder: 'asc' },
        });
      }

      // 2. Create stage category evaluations (score breakdown for each category)
      const categoryEvalData = await this.buildCategoryEvalData(result, dbSessionId);
      if (categoryEvalData.length > 0) {
        await tx.stageCategoryEval.createMany({ data: categoryEvalData });
      }

      // 3. Create session categories (multi-label support)
      const sessionCategoryData = await this.buildSessionCategoryData(result, dbSessionId);
      if (sessionCategoryData.length > 0) {
        await tx.sessionCategory.createMany({ data: sessionCategoryData });
      }

      // 4. Create detected attributes (attribute context)
      const attributeData = this.buildAttributeData(result.attributeContext, dbSessionId);
      if (attributeData.length > 0) {
        await tx.detectedAttribute.createMany({ data: attributeData });
      }

      // 5. Create extracted features (AI feature extraction data)
      // Only persist if AI routing was used and we have feature extraction data
      if (result.aiRoutingUsed && stageRecords.length > 0) {
        const extractedFeatureData = this.buildExtractedFeatureData(result, stageRecords);
        if (extractedFeatureData.length > 0) {
          await tx.extractedFeature.createMany({ data: extractedFeatureData });
        }
      }
    });
  } catch (error) {
    throw new Error(
      `Failed to save classification result for email ${result.emailId}: ${error instanceof Error ? error.message : String(error)}`
    );
  }
}

